import functools

def logged(fn):
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        print(f"-> {fn.__name__}{args}")
        return fn(*args, **kwargs)
    return wrapper

@logged
def add(a, b):
    """Add two numbers."""
    return a + b

print(add(2, 3))        # -> add(2, 3) then 5
print(add.__name__)     # 'add'  (preserved by functools.wraps)
print(add.__doc__)      # 'Add two numbers.'

import functools

def retry(times):
    def deco(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            last = None
            for _ in range(times):
                try:
                    return fn(*args, **kwargs)
                except Exception as e:
                    last = e
            raise RuntimeError("all attempts failed") from last
        return wrapper
    return deco

calls = {"n": 0}

@retry(times=3)
def flaky():
    calls["n"] += 1
    if calls["n"] < 3:
        raise ValueError("transient")
    return "ok"

print(flaky())   # ok (after 3 tries)

from functools import lru_cache

@lru_cache(maxsize=256)
def tokenize(text):
    print(f"computing for {text!r}")
    return text.split()

print(tokenize("gen ai"))   # computes
print(tokenize("gen ai"))   # cached -> no 'computing' line
print(tokenize.cache_info())

TOOLS = {}

def tool(fn):
    TOOLS[fn.__name__] = fn
    return fn        # return unchanged; just register it

@tool
def get_weather(city):
    return f"sunny in {city}"

print(list(TOOLS))                 # ['get_weather']
print(TOOLS["get_weather"]("Paris"))
